// ============================================================
// Activity Dashboard — Build HTML (v2: accordion + links + hygiene + team roles)
// ============================================================

// ── helpers ──────────────────────────────────────────────────
const fmt = n => (n == null ? '—' : Number(n).toLocaleString());
const fmtUsd = n => n == null ? '—' : '$' + Number(n).toLocaleString(undefined, {minimumFractionDigits:2, maximumFractionDigits:2});
const ago = ts => {
  if (!ts) return '—';
  const d = Math.floor((Date.now() - new Date(ts)) / 86400000);
  if (d === 0) return 'Today';
  if (d === 1) return '1d ago';
  return `${d}d ago`;
};
const fresh = ts => {
  if (!ts) return '<span style="color:#888">Unknown ⚪</span>';
  const d = Math.floor((Date.now() - new Date(ts)) / 86400000);
  if (d === 0) return '<span style="color:#22c55e">Fresh 🟢</span>';
  if (d === 1) return '<span style="color:#f59e0b">1d stale 🟡</span>';
  return `<span style="color:#ef4444">${d}d stale 🔴</span>`;
};
function esc(s) { return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

// ── pull data from all inputs ─────────────────────────────────
const sysHealth    = ($('BQ - System Health').all()[0] || {json:{}}).json;
const paidHealth   = $('BQ - Connector Health (Paid)').all().map(i => i.json);
const hsHealth     = $('BQ - Connector Health (HubSpot)').all().map(i => i.json);
const heatRows     = $('BQ - Heatmap').all().map(i => i.json);
const actFeed      = $('BQ - Activity Feed').all().map(i => i.json);
const openTasks    = $('BQ - Open Tasks').all().map(i => i.json);
const hygieneRows  = $('BQ - Data Hygiene').all().map(i => i.json);

// ── today ─────────────────────────────────────────────────────
const today = new Date().toLocaleDateString('en-GB', {day:'numeric',month:'short',year:'numeric', timeZone:'Asia/Riyadh'});

// ── agent definitions ─────────────────────────────────────────
const agents = [
  { name:'AI Orchestrator', color:'#f97316', dept:'MANAGER', trigger:'run daily / weekly / monthly', outputsTo:'All agents' },
  { name:'QA Auditor', color:'#ef4444', dept:'GATEKEEPER', trigger:'validate this output', outputsTo:'AI Orchestrator' },
  { name:'Project Coordinator', color:'#6b7280', dept:'OPS', trigger:'coordinate this campaign', outputsTo:'#approvals' },
  { name:'Performance Lead', color:'#3b82f6', dept:'PERFORMANCE', trigger:'set KPI thresholds / budget', outputsTo:'Campaign Manager + Creative Strategist' },
  { name:'Campaign Manager', color:'#0ea5e9', dept:'PERFORMANCE', trigger:'audit keywords / ads', outputsTo:'#approvals' },
  { name:'Creative Strategist', color:'#a855f7', dept:'PERFORMANCE', trigger:'brief creative', outputsTo:'#approvals' },
  { name:'CRO Specialist', color:'#f97316', dept:'CRO CHAIN', trigger:'LP brief / qual rate', outputsTo:'UI/UX Designer' },
  { name:'UI/UX Designer', color:'#fb923c', dept:'CRO CHAIN', trigger:'design LP', outputsTo:'Developer' },
  { name:'Developer', color:'#86efac', dept:'CRO CHAIN', trigger:'build LP / wire pixels', outputsTo:'#data-health' },
];

// ── dept color ─────────────────────────────────────────────────
const deptColor = { MANAGER:'#f97316', GATEKEEPER:'#ef4444', OPS:'#6b7280', PERFORMANCE:'#3b82f6', 'CRO CHAIN':'#22c55e' };

// ── helpers from original ─────────────────────────────────────
function stalenessColor(d) {
  if (d===null||d===undefined) return 'var(--muted)';
  const n = parseInt(d,10);
  if (isNaN(n)) return 'var(--muted)';
  return n===0 ? 'var(--green)' : n===1 ? 'var(--orange)' : '#e05c5c';
}

function fmtTs(tsStr) {
  if (!tsStr || tsStr==='null') return '—';
  try {
    const d = new Date(tsStr);
    return d.toLocaleString('en-GB',{timeZone:'UTC',month:'short',day:'2-digit',hour:'2-digit',minute:'2-digit',hour12:false}).replace(',','') + ' UTC';
  } catch(e) { return String(tsStr).substring(0,16); }
}

function freshnessStatus(tsStr) {
  if (!tsStr || tsStr==='null') return {color:'var(--muted)',label:'No data'};
  const now = new Date();
  const d = new Date(tsStr);
  const diffH = (now - d) / 3600000;
  if (diffH < 12) return {color:'var(--green)', label: Math.floor(diffH)+'h ago'};
  if (diffH < 24) return {color:'var(--orange)', label: Math.floor(diffH)+'h ago'};
  return {color:'#e05c5c', label: Math.floor(diffH)+'h ago'};
}

function agoStr(tsStr) {
  if (!tsStr) return '—';
  const now = new Date();
  const d = new Date(tsStr);
  const m = Math.floor((now - d) / 60000);
  if (m < 60) return m+'m ago';
  if (m < 1440) return Math.floor(m/60)+'h ago';
  return Math.floor(m/1440)+'d ago';
}

// ── build sections ────────────────────────────────────────────

// System Health Bar (preserved from original)
const N8N_BASE = 'https://qoyod.app.n8n.cloud/workflow';
const N8N_WORKFLOWS = {
  orchestrator: 'T8icImtZFLYeCa7e', weekly: 'iNSdpXH7Rc9Lb8h8',
  monthly: '0Zh45UoTtjjhRn8U', growth_analyst: 'MHCdIiAtKzHNve1x',
  perf_lead: 'Qd5SoGxZbgT1ohYP', cro: 'jfE5KKnPJQBf7MCj',
  qual: 'PxFBmtXDVgcNGzIM', campaign_mgr: 'eL0V6ReftV2U1wNf',
  creative: 'smHaEhWloComRQyz', qa: 'ug3niLKrjPfO9Iz7',
  data_collection: 'jOnJxdpdaO3Vbi0B', approval: '5Acqsbxsk0XQ5k9e'
};

const fr = freshnessStatus(sysHealth.last_ts);
const dot = c => `<span class="hdot" style="background:${c};box-shadow:0 0 5px ${c}"></span>`;
const nowUtc = new Date();
let next8 = new Date(nowUtc);
next8.setUTCHours(5,0,0,0);
if (nowUtc >= next8) next8 = new Date(next8.getTime() + 86400000);
const diffMs = next8 - nowUtc;
const nextH = Math.floor(diffMs/3600000);
const nextM = Math.floor((diffMs%3600000)/60000);

const healthBar = `<div class="hbar">
  <div class="hchip">${dot(fr.color)}<span class="hlabel">BQ Activity</span><span class="hval" style="color:${fr.color}">${fr.label}</span></div>
  <div class="hchip">${dot('var(--green)')}<span class="hlabel">n8n Master</span><span class="hval" style="color:var(--muted)">Daily 08:00 AST</span></div>
  <div class="hchip">${dot('var(--green)')}<span class="hlabel">GitHub Actions</span><span class="hval" style="color:var(--muted)">Every 6h</span></div>
  <div class="hchip">${dot('var(--green)')}<span class="hlabel">GitHub Pages</span><span class="hval" style="color:var(--green)">Serving</span></div>
  <div class="hchip"><span class="hlabel">⏳ Next run in</span><span class="hval" style="color:var(--muted)">${nextH}h ${nextM}m</span></div>
  <div class="hchip"><a href="${N8N_BASE}/${N8N_WORKFLOWS.data_collection}" target="_blank" class="n8n-link">Data Collection →</a></div>
  <div class="hchip"><a href="${N8N_BASE}/${N8N_WORKFLOWS.approval}" target="_blank" class="n8n-link">Approval Listener →</a></div>
</div>`;

// Connector cards
const bqToSlug = {
  'Google Ads':'google_ads','Meta':'meta','Meta Ads':'meta',
  'Snapchat':'snapchat','Snapchat Ads':'snapchat',
  'TikTok':'tiktok','TikTok Ads':'tiktok',
  'LinkedIn':'linkedin','LinkedIn Ads':'linkedin',
  'Microsoft Ads':'microsoft_ads','Bing Ads':'microsoft_ads',
  'hubspot_leads':'hubspot_leads','hubspot_deals':'hubspot_deals'
};
const CONNECTORS = [
  ['Google Ads','google_ads'],['Meta','meta'],['Snapchat','snapchat'],
  ['TikTok','tiktok'],['LinkedIn','linkedin'],['Microsoft Ads','microsoft_ads'],
  ['HubSpot Leads','hubspot_leads'],['HubSpot Deals','hubspot_deals']
];
const slugMap = {};
[...paidHealth, ...hsHealth].forEach(r => {
  const slug = bqToSlug[r.channel] || (r.channel||'').toLowerCase().replace(/\s+/g,'_');
  slugMap[slug] = r;
});
const connCards = CONNECTORS.map(([name, key]) => {
  const info = slugMap[key] || {};
  const lastDate = info.last_date || null;
  const daysStale = info.days_stale !== undefined ? info.days_stale : null;
  const color = stalenessColor(daysStale);
  const dateStr = lastDate ? String(lastDate).substring(0,10) : 'No data';
  const staleStr = daysStale===null ? '—' : (parseInt(daysStale)===0 ? 'Fresh' : `${parseInt(daysStale)}d stale`);
  return `<div class="conn-card">
  <div class="conn-top"><span class="conn-name">${esc(name)}</span><span class="conn-dot" style="background:${color};box-shadow:0 0 4px ${color}"></span></div>
  <div class="conn-ts">${dateStr}</div>
  <div class="conn-status" style="color:${color}">${staleStr}</div>
</div>`;
}).join('\n');

// Heatmap (preserved from original)
const DOW_LABELS = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];
const DOW_ORDER  = [2,3,4,5,6,7,1];
const heatLookup = {};
heatRows.forEach(r => { heatLookup[`${r.dow}_${r.hr}`] = parseInt(r.cnt)||0; });
const maxCnt = Math.max(1, ...Object.values(heatLookup).concat([1]));
const hourHeaders = Array.from({length:24},(_,h)=>`<th class="hm-h">${String(h).padStart(2,'0')}</th>`).join('');
const heatRowsHtml = DOW_ORDER.map((dow,i) => {
  const cells = Array.from({length:24},(_,hr) => {
    const cnt = heatLookup[`${dow}_${hr}`]||0;
    const alpha = cnt ? (cnt/maxCnt).toFixed(2) : '0';
    const bg = cnt ? `rgba(0,255,136,${alpha})` : 'var(--border)';
    return `<td class="hm-cell" style="background:${bg}" title="${cnt} events"></td>`;
  }).join('');
  return `<tr><th class="hm-row">${DOW_LABELS[i]}</th>${cells}</tr>`;
}).join('');
const heatmap = `<div class="hm-wrap"><table class="hm-table"><thead><tr><th></th>${hourHeaders}</tr></thead><tbody>${heatRowsHtml}</tbody></table>
<div class="hm-legend"><span style="color:var(--muted);font-size:11px">Less</span><div class="hm-grad"></div><span style="color:var(--muted);font-size:11px">More</span><span style="color:var(--muted);font-size:11px;margin-left:16px">Asia/Riyadh · last 7 days</span></div></div>`;

// Activity feed (preserved from original)
const STATUS_COLOR = {
  success:'var(--green)',failed:'#e05c5c',skipped:'var(--muted)',
  pending_approval:'var(--orange)',approved:'var(--green)',rejected:'#e05c5c'
};
const activityFeed = actFeed.length
  ? actFeed.map(r => {
    const color = STATUS_COLOR[(r.status||'').toLowerCase()] || 'var(--dim)';
    const chTag = r.channel ? `<span class="feed-ch">${esc(r.channel)}</span>` : '';
    return `<div class="feed-row"><span class="feed-ts">${fmtTs(r.ts)}</span><span class="feed-role">${esc(r.role)}</span>${chTag}<span class="feed-action">${esc(r.action)}</span><span class="feed-badge" style="color:${color};border-color:${color}">${esc(r.status)}</span></div>`;
  }).join('')
  : '<div class="feed-empty">No activity in the last 7 days — BQ may be unreachable</div>';

// Open Tasks with Asana links
const todayStr = new Date(new Date().getTime()+3*3600000).toISOString().substring(0,10);
const taskRows = openTasks.map(t => {
  const gid = t.gid || '';
  const name = esc(t.title || '—');
  const link = gid
    ? `<a href="https://app.asana.com/0/0/${gid}" target="_blank" style="color:var(--orange);text-decoration:none">${name}</a>`
    : name;
  const due = t.due_on ? String(t.due_on).substring(0,10) : null;
  const overdue = due && due < todayStr;
  const dueHtml = due
    ? `<span style="color:${overdue ? '#ef4444' : 'var(--muted)'}">${due}</span>`
    : '—';
  const assign = t.assignee_name ? esc(t.assignee_name) : '—';
  const proj = t.project_key ? esc(t.project_key) : '—';
  return `<tr><td>${link}</td><td>${assign}</td><td>${dueHtml}</td><td>${proj}</td></tr>`;
}).join('') || '<tr><td colspan="4" style="color:var(--muted);text-align:center">No open tasks</td></tr>';

// Data Hygiene cards
const hygieneCards = hygieneRows.map(r => {
  return `<div class="conn-card">
  <div class="conn-top"><span class="conn-name">${esc(r.table_name)}</span></div>
  <div class="conn-ts">${fmt(r.row_count)} rows</div>
  <div class="conn-status">${fresh(r.last_modified)}</div>
</div>`;
}).join('\n') || '<div style="color:var(--muted)">No hygiene data</div>';

// Team role cards
const teamRoleCards = agents.map(a => {
  const dc = deptColor[a.dept] || '#888';
  return `<div class="role-card" style="border-left-color:${a.color}">
  <div style="font-size:14px;font-weight:700;color:${a.color};margin-bottom:6px">${esc(a.name)}</div>
  <div style="display:inline-block;font-size:10px;padding:2px 7px;border-radius:10px;font-weight:700;margin-bottom:8px;background:${dc};color:#000">${esc(a.dept)}</div>
  <div style="font-size:11px;color:var(--dim);margin-top:4px"><strong style="color:var(--text)">Trigger:</strong> ${esc(a.trigger)}</div>
  <div style="font-size:11px;color:var(--dim);margin-top:4px"><strong style="color:var(--text)">Outputs to:</strong> ${esc(a.outputsTo)}</div>
</div>`;
}).join('');

const approvalsChannelId = 'C0AT1AP8TJ4';
const approvalsUrl = `https://qoyod.slack.com/channels/${approvalsChannelId}`;
const nowStr = new Date().toLocaleString('en-GB',{timeZone:'Asia/Riyadh',day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit',hour12:false}).replace(',','') + ' AST';

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<meta http-equiv="refresh" content="3600">
<title>Nexa Performance Agent — Activity Dashboard</title>
<style>
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{
  --bg:#0d0d0d;--card:#1a1a1a;--panel:#141414;--border:#2a2a2a;
  --text:#e6e6e6;--dim:#aaa;--muted:#888;
  --blue:#58a6ff;--lblue:#79c0ff;--purple:#d2a8ff;
  --orange:#f0883e;--warm-orange:#ffa657;--green:#3fb950;--lgreen:#7ee787;
  --grey:#8b949e;--red:#f85149;--accent:#00ff88;
}
body{background:var(--bg);color:var(--text);font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;font-size:14px;line-height:1.5;min-height:100vh}
a{color:inherit;text-decoration:none}
a:hover{text-decoration:underline}
header{display:flex;align-items:center;gap:10px;padding:16px 24px;border-bottom:1px solid var(--border);background:#111;position:sticky;top:0;z-index:100}
header h1{font-size:16px;font-weight:600;letter-spacing:.3px}
.dot{width:8px;height:8px;border-radius:50%;background:var(--accent);box-shadow:0 0 6px var(--accent);flex-shrink:0}
.htag{margin-left:auto;font-size:11px;color:var(--muted);background:#222;padding:3px 8px;border-radius:4px;border:1px solid var(--border)}
main{max-width:1160px;margin:0 auto;padding:28px 20px 60px}
.toggle-all{font-size:11px;color:var(--orange);cursor:pointer;background:none;border:1px solid var(--orange);padding:4px 10px;border-radius:4px;margin-left:auto}
.sec{font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:1.2px;color:var(--muted);margin:32px 0 0;display:flex;align-items:center;gap:8px;cursor:pointer;user-select:none}
.sec::after{content:"";flex:1;height:1px;background:var(--border)}
.sec .sec-arrow{font-size:9px;transition:transform 0.15s}
.section-body{overflow:hidden;transition:max-height 0.25s ease;margin-bottom:4px}
.section-body.collapsed{max-height:0!important}
/* Health bar */
.hbar{display:flex;flex-wrap:wrap;gap:10px;margin:14px 0 4px}
.hchip{display:flex;align-items:center;gap:7px;background:var(--card);border:1px solid var(--border);border-radius:20px;padding:6px 14px;font-size:12px}
.hdot{width:8px;height:8px;border-radius:50%;flex-shrink:0}
.hlabel{color:var(--dim)}
.hval{font-weight:600}
/* Connector & hygiene cards */
.conn-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin:14px 0 4px}
@media(max-width:900px){.conn-grid{grid-template-columns:repeat(2,1fr)}}
@media(max-width:520px){.conn-grid{grid-template-columns:1fr}}
.conn-card{background:var(--card);border:1px solid var(--border);border-radius:8px;padding:14px 16px;display:flex;flex-direction:column;gap:5px}
.conn-top{display:flex;align-items:center;justify-content:space-between}
.conn-name{font-size:13px;font-weight:600}
.conn-dot{width:8px;height:8px;border-radius:50%;flex-shrink:0}
.conn-ts{font-size:11px;color:var(--muted)}
.conn-status{font-size:11px;font-weight:600}
/* Heatmap */
.hm-wrap{overflow-x:auto;margin:14px 0 4px}
.hm-table{border-collapse:collapse;font-size:10px}
.hm-h{color:var(--muted);padding:2px 3px;text-align:center;font-weight:400;width:22px}
.hm-row{color:var(--dim);padding:2px 8px 2px 0;text-align:right;font-size:11px;white-space:nowrap;font-weight:500}
.hm-cell{width:22px;height:18px;border-radius:3px;cursor:default}
.hm-legend{display:flex;align-items:center;gap:8px;margin-top:8px}
.hm-grad{width:80px;height:10px;border-radius:4px;background:linear-gradient(to right,var(--border),var(--accent))}
/* Activity feed */
.feed-wrap{background:var(--card);border:1px solid var(--border);border-radius:8px;overflow:hidden;margin:14px 0 4px}
.feed-row{display:flex;align-items:center;gap:10px;padding:8px 12px;border-bottom:1px solid var(--border);font-size:12px;flex-wrap:wrap}
.feed-row:last-child{border-bottom:none}
.feed-ts{color:var(--muted);white-space:nowrap;min-width:110px}
.feed-role{color:var(--blue);font-weight:600;min-width:120px}
.feed-ch{background:#1f1f1f;color:var(--dim);border:1px solid var(--border);border-radius:4px;padding:1px 6px;font-size:10px}
.feed-action{flex:1;color:var(--text)}
.feed-badge{font-size:10px;font-weight:700;text-transform:uppercase;padding:2px 7px;border-radius:10px;border:1px solid;white-space:nowrap}
.feed-empty{color:var(--muted);font-size:12px;padding:16px}
/* Open Tasks table */
.tasks-wrap{margin:14px 0 4px}
table{width:100%;border-collapse:collapse}
th{text-align:left;font-size:11px;color:var(--muted);padding:8px 10px;border-bottom:1px solid var(--border);font-weight:600}
td{padding:9px 10px;border-bottom:1px solid var(--border);vertical-align:middle;font-size:13px}
tr:last-child td{border-bottom:none}
tr:hover td{background:rgba(255,255,255,0.02)}
/* Cadence */
.cgrid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin:14px 0 4px}
@media(max-width:700px){.cgrid{grid-template-columns:1fr}}
.ccard{background:var(--card);border:1px solid var(--border);border-radius:8px;padding:14px 16px;display:flex;justify-content:space-between;align-items:flex-start;gap:12px}
.cname{font-size:13px;font-weight:600}
.cdesc{font-size:11px;color:var(--muted);margin-top:3px}
.csched{font-size:11px;color:var(--muted);background:#111;padding:3px 8px;border-radius:4px;font-family:monospace;white-space:nowrap;flex-shrink:0}
.n8n-link{color:#f0883e;font-size:11px;text-decoration:none;border:1px solid #f0883e44;padding:2px 8px;border-radius:4px;white-space:nowrap}
.n8n-link:hover{background:#f0883e22}
/* Team roles */
.role-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:12px;margin:14px 0 4px}
.role-card{background:var(--card);border:1px solid var(--border);border-left-width:3px;border-radius:8px;padding:14px}
/* Approval footer */
.approval-footer{margin-top:24px;padding:14px;background:var(--card);border:1px solid var(--border);border-radius:8px;font-size:13px}
</style>
</head>
<body>

<header>
  <div class="dot"></div>
  <h1>Nexa Performance Agent</h1>
  <span class="htag">n8n Cloud · GitHub Pages · ${nowStr}</span>
  <button id="toggle-all" class="toggle-all">Collapse All</button>
</header>

<main>

<!-- SYSTEM HEALTH -->
<div class="sec" id="sec-h-0"><span class="sec-arrow">▾</span>&nbsp;System Health</div>
<div class="section-body" id="sec-0">${healthBar}</div>

<!-- CONNECTOR HEALTH -->
<div class="sec" id="sec-h-1"><span class="sec-arrow">▾</span>&nbsp;Connector Health</div>
<div class="section-body" id="sec-1">
  <div class="conn-grid">${connCards}</div>
</div>

<!-- DATA HYGIENE -->
<div class="sec" id="sec-h-2"><span class="sec-arrow">▾</span>&nbsp;Data Hygiene</div>
<div class="section-body" id="sec-2">
  <div class="conn-grid">${hygieneCards}</div>
</div>

<!-- ACTIVITY HEATMAP -->
<div class="sec" id="sec-h-3"><span class="sec-arrow">▾</span>&nbsp;Activity Heat Map — Last 7 Days</div>
<div class="section-body" id="sec-3">${heatmap}</div>

<!-- RECENT AGENT ACTIVITY -->
<div class="sec" id="sec-h-4"><span class="sec-arrow">▾</span>&nbsp;Recent Agent Activity</div>
<div class="section-body" id="sec-4">
  <div class="feed-wrap">${activityFeed}</div>
</div>

<!-- OPEN TASKS -->
<div class="sec" id="sec-h-5"><span class="sec-arrow">▾</span>&nbsp;Open Asana Tasks</div>
<div class="section-body" id="sec-5">
  <div class="tasks-wrap">
    <table>
      <thead><tr><th>Title</th><th>Assignee</th><th>Due</th><th>Project</th></tr></thead>
      <tbody>${taskRows}</tbody>
    </table>
  </div>
</div>

<!-- CADENCE FLOWS -->
<div class="sec" id="sec-h-6"><span class="sec-arrow">▾</span>&nbsp;Cadence Flows</div>
<div class="section-body" id="sec-6">
  <div class="cgrid">
    <div class="ccard">
      <div>
        <div class="cname">Daily Master</div>
        <div class="cdesc">Full daily analysis: spend, leads, CPQL, anomaly detection, Slack summary, pause/scale candidates</div>
        <div style="margin-top:8px"><a href="${N8N_BASE}/${N8N_WORKFLOWS.orchestrator}" target="_blank" class="n8n-link">Open Daily in n8n →</a></div>
      </div>
