<script>
const secs = document.querySelectorAll('.sec[id^="sec-h-"]');
secs.forEach(function(sec, i) {
  const body = document.getElementById('sec-' + i);
  if (!body) return;
  body.style.maxHeight = body.scrollHeight + 'px';
  sec.addEventListener('click', function() {
    const collapsed = sec.classList.toggle('collapsed');
    body.classList.toggle('collapsed', collapsed);
    if (!collapsed) body.style.maxHeight = body.scrollHeight + 'px';
    const arrow = sec.querySelector('.sec-arrow');
    if (arrow) arrow.textContent = collapsed ? '▸' : '▾';
  });
});
document.getElementById('toggle-all').addEventListener('click', function() {
  const allOpen = [...document.querySelectorAll('.section-body')].every(function(b) { return !b.classList.contains('collapsed'); });
  document.querySelectorAll('.sec[id^="sec-h-"]').forEach(function(s) {
    s.classList.toggle('collapsed', allOpen);
    const arrow = s.querySelector('.sec-arrow');
    if (arrow) arrow.textContent = allOpen ? '▸' : '▾';
  });
  document.querySelectorAll('.section-body').forEach(function(b) {
    b.classList.toggle('collapsed', allOpen);
    if (!allOpen) b.style.maxHeight = b.scrollHeight + 'px';
  });
  this.textContent = allOpen ? 'Expand All' : 'Collapse All';
});
